import{c as a,Q as t,j as i,m as r}from"./chunks/framework.DVP2LVsd.js";const m=JSON.parse('{"title":"Integrations","description":"","frontmatter":{},"headers":[],"relativePath":"api/integrations/index.md","filePath":"api/integrations/index.md","lastUpdated":1781370958000}'),s={name:"api/integrations/index.md"};function o(n,e,d,l,h,g){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to &quot;Integrations&quot;">​</a></h1><p>LibrisLog exposes a full REST API that third-party applications can use to display your reading data, automate workflows, or build custom dashboards.</p><p>All integrations below are backed by the LibrisLog API. You will need an API key to use them. You can create one either:</p><p><span id="api-keys"></span></p><ul><li><strong>Via the web UI</strong> — go to your <a href="/next/api/#creating-an-api-key">Profile</a> page and click &quot;Create API Key&quot;.</li><li><strong>Via the API</strong> — see the <a href="/next/api/setup.html#3-create-an-api-key">Headless Setup</a> guide for a CLI-based workflow.</li></ul><h2 id="embed-widgets-no-header-auth" tabindex="-1">Embed Widgets (No Header Auth) <a class="header-anchor" href="#embed-widgets-no-header-auth" aria-label="Permalink to &quot;Embed Widgets (No Header Auth)&quot;">​</a></h2><p>Some dashboards only support iframe widgets and cannot set custom HTTP headers. For these integrations you need an <strong>embed token</strong>, used with the <a href="/next/api/integrations/embed-api.html">Embed API</a>:</p><p><span id="embed-tokens"></span></p><ul><li><strong>Create one</strong> from your <a href="/next/guide/using-librislog/profile.html">Profile page</a> under &quot;Embed Tokens&quot;.</li><li>Embed tokens are <strong>scoped to embed endpoints only</strong> and can be revoked or rotated independently of API keys.</li><li>They are passed as query parameter (<code>?token=...</code>) in the widget URL.</li></ul><h2 id="available-integrations" tabindex="-1">Available Integrations <a class="header-anchor" href="#available-integrations" aria-label="Permalink to &quot;Available Integrations&quot;">​</a></h2><ul><li><a href="/next/api/integrations/embed-api.html">Embed API</a> — Generic embed widget API for iframe-based dashboards. Uses scoped embed tokens and supports custom styling.</li><li><a href="/next/api/integrations/dashy.html">Dashy</a> — Display your LibrisLog statistics as styled stat cards on a <a href="https://dashy.to/" target="_blank" rel="noreferrer">Dashy</a> dashboard using the HTML embedded widget.</li><li><a href="/next/api/integrations/glance.html">Glance</a> — Display your LibrisLog statistics on a <a href="https://github.com/glanceapp/glance" target="_blank" rel="noreferrer">Glance</a> dashboard using the custom API widget.</li><li><a href="/next/api/integrations/homeassistant.html">Home Assistant</a> — Expose your LibrisLog reading statistics as sensors in <a href="https://www.home-assistant.io/" target="_blank" rel="noreferrer">Home Assistant</a> using the RESTful integration.</li><li><a href="/next/api/integrations/homarr.html">Homarr</a> — Display your LibrisLog statistics on a <a href="https://homarr.dev/" target="_blank" rel="noreferrer">Homarr</a> dashboard using the iframe widget.</li><li><a href="/next/api/integrations/homepage.html">Homepage</a> — Display your LibrisLog statistics on a <a href="https://gethomepage.dev/" target="_blank" rel="noreferrer">Homepage</a> dashboard using the custom API widget.</li></ul>',11)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
